INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('1709d0a13771a742', 'MI', '["state"]', 'election_dates', 'Are the Governor, Secretary of State, and Attorney General on the 2026 ballot?', '["2026 statewide executive races","Is Whitmer running in 2026?","What statewide offices are up this cycle?"]', 'Yes. The Governor, Lieutenant Governor, Secretary of State, and Attorney General are all on the 2026 ballot. Because the current incumbents (Whitmer, Gilchrist, Benson, Nessel) were elected in 2018 and re-elected in 2022, they are constitutionally term-limited, making these all open seats.', 'http://legislature.mi.gov/doc.aspx?mcl-Article-V-30', 'Michigan Constitution, Article V, Section 30', '2026-05-11', 'static', 'statute_citation', 'Applies to candidate and voter awareness for the 2026 statewide cycle.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('352e73eca084bdfe', 'MI', '["federal"]', 'election_dates', 'Which U.S. Senate seat is on the Michigan ballot in 2026?', '["US Senate election MI 2026","Is Gary Peters up for reelection?","Federal statewide races 2026"]', 'Michigan''s Class 2 U.S. Senate seat, currently held by Gary Peters, is on the ballot for the 2026 general election.', 'https://www.michigan.gov/sos/elections/candidates', 'Michigan Secretary of State – Candidate Information', '2026-05-11', 'static', 'official_source_direct', 'Applies to candidate and voter awareness for the 2026 cycle.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('0c483829e14d7c43', 'MI', '["state"]', 'election_dates', 'Which Michigan State Senate seats are on the ballot in 2026?', '["PA Senate staggered terms","Are all state senators elected at once?","2026 state senate districts"]', 'Unlike some other states, Michigan State Senate terms are NOT staggered. All 38 State Senate seats serve concurrent four-year terms that align with the gubernatorial cycle, meaning all 38 seats are on the 2026 ballot.', 'http://legislature.mi.gov/doc.aspx?mcl-Article-IV-2', 'Michigan Constitution, Article IV, Section 2', '2026-05-11', 'static', 'statute_citation', 'Applies to candidates for the Michigan State Senate.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('f3fb91d428e9faae', 'MI', '["state"]', 'election_dates', 'Are all Michigan State House seats on the ballot in 2026?', '["How many state rep seats are up?","State House of Representatives cycle","2026 state house elections"]', 'Yes. All 110 seats in the Michigan House of Representatives serve two-year terms and are on the ballot for every even-year election cycle, including 2026.', 'http://legislature.mi.gov/doc.aspx?mcl-Article-IV-3', 'Michigan Constitution, Article IV, Section 3', '2026-05-11', 'static', 'statute_citation', 'Applies to candidates for the Michigan House of Representatives.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('8f84bbcd2e6430c7', 'MI', '["state"]', 'candidate_eligibility', 'What are the term limits for the Michigan State Legislature?', '["How many terms can a state rep serve?","Proposal 1 of 2022 term limits","State senate term limits"]', 'Under Proposal 1, a person may serve a combined total of 12 years across the House and Senate. However, there is a grandfather clause: anyone elected to the State Senate in 2022 is permitted to serve their two full terms (8 years), even if their prior House service pushes them over the 12-year combined limit.', 'http://legislature.mi.gov/doc.aspx?mcl-Article-IV-54', 'Michigan Constitution, Article IV, Section 54', '2026-05-11', 'static', 'statute_citation', 'Applies to all candidates for the Michigan General Assembly.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('27c2b8634a8d6c94', 'MI', '["federal","state","county","municipal","judicial"]', 'election_dates', 'When is the 2026 Primary Election in Michigan?', '["MI primary date 2026","When do voters vote in the primary?","August primary date"]', 'The Michigan primary election is statutorily held on the first Tuesday in August of even-numbered years. For the 2026 cycle, this is Tuesday, August 4, 2026.', 'http://legislature.mi.gov/doc.aspx?mcl-168-534', 'MCL § 168.534', '2026-05-11', 'per_cycle', 'statute_citation', 'Applies to all voters and candidates on the primary ballot.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('fb589c898e0174e4', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When is the 2026 General Election in Michigan?', '["Election day 2026","What date is the November election?","Fall general election date"]', 'The 2026 General Election will be held on Tuesday, November 3, 2026.', 'http://legislature.mi.gov/doc.aspx?mcl-168-641', 'MCL § 168.641', '2026-05-11', 'per_cycle', 'statute_citation', 'Applies to all voters and candidates.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('7ab63598279c2284', 'MI', '["federal","state","county","judicial"]', 'ballot_access', 'When is the candidate filing period deadline for the August 2026 primary?', '["When do I file for office?","Qualifying deadline 2026","Nominating petition deadline"]', 'Under Michigan law, candidates must file their nominating petitions and Affidavit of Identity no later than 4:00 p.m. on the 15th Tuesday before the August primary. For the August 4, 2026 primary, the filing deadline is Tuesday, April 21, 2026.', 'http://legislature.mi.gov/doc.aspx?mcl-168-163', 'MCL § 168.163(1)', '2026-05-11', 'per_cycle', 'statute_citation', 'Applies to candidates seeking primary ballot access.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('3430216966fbe988', 'MI', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Are Michigan primary elections open or closed to independent voters?', '["Do I have to register as a Republican to vote in the primary?","Party registration rules","Open primary state"]', 'Michigan operates an open primary system and does NOT have partisan voter registration. A registered voter does not need to declare a party in advance; they simply request either the Republican or Democratic ballot at the polling place on primary day.', 'http://legislature.mi.gov/doc.aspx?mcl-168-576', 'MCL § 168.576', '2026-05-11', 'static', 'statute_citation', 'Applies to all voters participating in primary elections.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('d2a444865f0d25ec', 'MI', '["federal","state","county","municipal","judicial"]', 'runoff_rules', 'Does Michigan hold primary runoffs if no candidate gets 50%?', '["Primary runoff threshold","What happens in a crowded primary?","Do I need a majority to win the nomination?"]', 'No. Michigan does not hold runoff elections. The candidate who receives the highest number of votes (a simple plurality) in the primary election becomes the party''s nominee, even if they do not secure a majority.', 'http://legislature.mi.gov/doc.aspx?mcl-168-581', 'MCL § 168.581', '2026-05-11', 'static', 'statute_citation', 'Applies to all partisan primary elections.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('ab28e997a8a44956', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Does Michigan have early in-person voting?', '["When does early voting start?","In-person early voting dates","Proposal 2 early voting window"]', 'Yes. Following the passage of Proposal 2 in 2022, the Michigan Constitution guarantees voters the right to at least nine (9) consecutive days of early in-person voting, beginning on the second Saturday before the election and ending on the Sunday before the election.', 'http://legislature.mi.gov/doc.aspx?mcl-Article-II-4', 'Michigan Constitution, Article II, Section 4(1)(m)', '2026-05-11', 'static', 'statute_citation', 'Applies to all voters seeking to cast an in-person ballot before Election Day.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('2ccee75be54e0f90', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Does Michigan allow any voter to vote by mail without an excuse?', '["No-excuse absentee voting","Proposal 3 mail voting rules","Can anyone get a mail ballot?"]', 'Yes. Since the passage of Proposal 3 in 2018 (and reinforced by Proposal 2 in 2022), every registered voter in Michigan has the constitutional right to request and cast an absentee ballot without providing a reason.', 'http://legislature.mi.gov/doc.aspx?mcl-Article-II-4', 'Michigan Constitution, Article II, Section 4(1)(g)', '2026-05-11', 'static', 'statute_citation', 'Applies to all registered voters in Michigan.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('6f7ee6d503e7199e', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Are absentee ballot drop boxes allowed or mandated in Michigan?', '["Where are the drop boxes?","Can I drop off my mail ballot?","Proposal 2 drop box rules"]', 'They are constitutionally mandated. Every municipality must have at least one state-funded secure drop box. Furthermore, for municipalities with more than 15,000 registered voters, there must be at least one drop box for every 15,000 registered voters.', 'http://legislature.mi.gov/doc.aspx?mcl-Article-II-4', 'Michigan Constitution, Article II, Section 4(1)(k)', '2026-05-11', 'static', 'statute_citation', 'Applies to voters returning mail ballots and municipal election clerks.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('584baa86e76e4a8f', 'MI', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the maximum individual contribution limit for a statewide candidate?', '["How much can one person donate to governor?","Maximum campaign contribution cap","Individual donor limits statewide"]', 'For the 2025-2026 cycle, an individual may contribute a maximum of $8,325 per election cycle to a candidate for statewide office (such as Governor, Attorney General, or Secretary of State). Note that Michigan frames limits ''per cycle'', not ''per election''.', 'https://www.michigan.gov/sos/elections/disclosure/cfr/limits', 'Michigan Bureau of Elections – Contribution Limits', '2026-05-11', 'per_cycle', 'official_source_direct', 'Applies to individuals donating to statewide candidates.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('0dfd0e9df610ae8e', 'MI', '["state"]', 'finance_ethics', 'What is the maximum individual contribution limit for a State Senate or State House candidate?', '["How much can one person donate to a legislator?","State rep contribution limits","Individual donor limits for general assembly"]', 'For the 2025-2026 cycle, an individual may contribute a maximum of $2,450 per election cycle to a candidate for State Senate, and $1,225 per election cycle to a candidate for State House.', 'https://www.michigan.gov/sos/elections/disclosure/cfr/limits', 'Michigan Bureau of Elections – Contribution Limits', '2026-05-11', 'per_cycle', 'official_source_direct', 'Applies to individuals donating to legislative candidates.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('e07f1cd6ee794ef5', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can a corporation donate directly to my campaign?', '["Are corporate contributions legal?","Can a business write a campaign check?","Corporate donation ban"]', 'No. Under the Michigan Campaign Finance Act, corporations, joint stock companies, domestic dependent sovereigns, and labor organizations are strictly prohibited from making direct contributions to candidate committees.', 'http://legislature.mi.gov/doc.aspx?mcl-169-254', 'MCL § 169.254(1)', '2026-05-11', 'static', 'statute_citation', 'Applies to candidate campaigns and corporate entities.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('3925ca969f068378', 'MI', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How much can a PAC donate to a state or local campaign?', '["PAC contribution limits","Political committee donation caps","Independent PAC limits"]', 'If a PAC qualifies as an ''Independent PAC'' (receiving money from 25+ persons and donating to 3+ candidates), it can contribute exactly 10 times the individual limit (e.g., $83,250 to Governor; $24,500 to State Senate; $12,250 to State House). Standard non-independent PACs face the same limits as individuals.', 'http://legislature.mi.gov/doc.aspx?mcl-169-252', 'MCL § 169.252(3)', '2026-05-11', 'per_cycle', 'statute_citation', 'Applies to PACs donating to state and local campaigns.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('6c415e8b4a8bc336', 'MI', '["federal","state"]', 'redistricting', 'Who draws the congressional and legislative district maps in Michigan?', '["Who controls redistricting?","Michigan Independent Citizens Redistricting Commission","MICRC overview"]', 'Redistricting in Michigan is handled entirely by the Michigan Independent Citizens Redistricting Commission (MICRC), a 13-member body (4 Republicans, 4 Democrats, 5 independents) established by constitutional amendment to remove map-drawing from the legislature.', 'http://legislature.mi.gov/doc.aspx?mcl-Article-IV-6', 'Michigan Constitution, Article IV, Section 6', '2026-05-11', 'static', 'statute_citation', 'Applies to the structure of Michigan''s political boundaries.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('2a6d84be9ddb7db4', 'MI', '["state"]', 'redistricting', 'Are the state legislative maps locked in for the 2026 election cycle?', '["Current redistricting map","Did the federal court change the district lines?","Agee v. Benson litigation status"]', 'Yes. Following the federal court ruling in Agee v. Benson that struck down several Detroit-area districts, the MICRC drew and adopted the remedial ''Motown Sound FC3'' State Senate map in June 2024, which the court approved as the active map for the 2026 cycle.', 'https://www.michigan.gov/micrc', 'Michigan Independent Citizens Redistricting Commission', '2026-05-11', 'static', 'official_source_direct', 'Applies to all candidates and voters navigating district boundaries in Metro Detroit.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('25bf4212fddbab65', 'MI', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What is the Affidavit of Identity (AOI) requirement?', '["What official forms must I file?","Notice of candidacy form","Missing the AOI deadline"]', 'Every candidate seeking ballot access must file an Affidavit of Identity (AOI) strictly detailing their name, address, and affirming they have paid all outstanding campaign finance fines. Failing to file the AOI exactly as required guarantees removal from the ballot.', 'http://legislature.mi.gov/doc.aspx?mcl-168-558', 'MCL § 168.558', '2026-05-11', 'static', 'statute_citation', 'Applies to all candidates qualifying for the ballot.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('594c57f9e65c480e', 'MI', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'Does Michigan have a ''Sore Loser'' law preventing me from running as an independent if I lose the primary?', '["Can a primary loser run in the general?","Running as unaffiliated after losing","Sore loser prohibitions"]', 'Yes. A candidate who is defeated in a political party primary is legally prohibited from running as a write-in candidate or an independent candidate for the same office in the subsequent general election.', 'http://legislature.mi.gov/doc.aspx?mcl-168-695', 'MCL § 168.695', '2026-05-11', 'static', 'statute_citation', 'Applies to candidates defeated in a partisan primary.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('3c0f1a02e85c0156', 'MI', '["state"]', 'ballot_access', 'How many petition signatures does a major party candidate need to run for Governor?', '["Primary signature requirement for Governor","How many signatures to run for statewide office?","Gubernatorial petition threshold"]', 'To qualify for the primary ballot, a candidate for Governor must submit a minimum of 15,000 valid signatures, which must include at least 100 signatures from each of at least half of the state''s congressional districts (currently 7 districts).', 'http://legislature.mi.gov/doc.aspx?mcl-168-53', 'MCL § 168.53', '2026-05-11', 'static', 'statute_citation', 'Applies to major party candidates for Governor.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('f9ea5ec7dfd46802', 'MI', '["federal"]', 'ballot_access', 'How many petition signatures does a major party candidate need to run for U.S. House?', '["Primary signature requirement for Congress","How many signatures for US Rep?","Congressional district petition threshold"]', 'To qualify for the primary ballot, a major party candidate for the U.S. House of Representatives must gather a minimum of 1,000 valid signatures (and a maximum of 2,000) from registered voters within that specific congressional district.', 'http://legislature.mi.gov/doc.aspx?mcl-168-133', 'MCL § 168.133', '2026-05-11', 'static', 'statute_citation', 'Applies to major party candidates for the U.S. House.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('e21e8002743eca1f', 'MI', '["state","county"]', 'ballot_access', 'Can I pay a filing fee instead of gathering signatures to run for State Legislature or County office?', '["How much is the filing fee?","Avoiding petitions by paying","Cost to get on the ballot for General Assembly"]', 'Yes. Candidates for State Senator, State Representative, and standard county offices (including Sheriff, Clerk, Treasurer, Prosecutor, and Register of Deeds) may choose to pay a uniform, non-refundable $100 filing fee INSTEAD of collecting nominating petition signatures.', 'http://legislature.mi.gov/doc.aspx?mcl-168-163', 'MCL § 168.163(2) & § 168.193(1)', '2026-05-11', 'per_cycle', 'statute_citation', 'Applies to candidates for the General Assembly and county offices.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('28bd36c46553dd67', 'MI', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What happens if I want to withdraw my candidacy after I file?', '["How do I quit the race?","Removing my name from the ballot","Withdrawal procedures"]', 'A candidate may withdraw their candidacy by serving a written, sworn notice to the filing official no later than 4:00 p.m. on the third day after the last day for filing nominating petitions. After this deadline, the candidate''s name will remain on the ballot.', 'http://legislature.mi.gov/doc.aspx?mcl-168-164', 'MCL § 168.164', '2026-05-11', 'static', 'statute_citation', 'Applies to candidates wishing to officially terminate their campaign prior to printing.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('f37f468663cc9c92', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the voter registration deadline for the August 2026 Primary?', '["When do the voter registration books close for the primary?","Registration cutoff date for August","Last day to register to vote for the 2026 primary"]', 'The deadline to register to vote by mail or online is 15 days before the election (July 20, 2026). However, a voter may register in-person at their local clerk''s office with proof of residency up until 8:00 p.m. on Election Day (August 4, 2026).', 'http://legislature.mi.gov/doc.aspx?mcl-168-497', 'MCL § 168.497', '2026-05-11', 'per_cycle', 'statute_citation', 'Applies to unregistered voters seeking to vote in the primary.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('fa25f12e8a810b14', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the voter registration deadline for the November 2026 General Election?', '["When do the voter registration books close for the general?","Registration cutoff date for November","Last day to register to vote for the 2026 general"]', 'The deadline to register by mail or online is October 19, 2026 (15 days prior). Same-day in-person registration at the local clerk''s office with proof of residency is available through 8:00 p.m. on Election Day (November 3, 2026).', 'http://legislature.mi.gov/doc.aspx?mcl-168-497', 'MCL § 168.497', '2026-05-11', 'per_cycle', 'statute_citation', 'Applies to unregistered voters seeking to vote in the general election.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('07c120bf84d44def', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'When is the deadline to request and return an absentee mail ballot?', '["Last day to ask for a mail ballot","Mail ballot return deadline","Does postmark matter for mail ballots?"]', 'Absentee ballots may be requested by mail until 5:00 p.m. the Friday before the election. Under Proposal 2, military/overseas ballots postmarked by Election Day are granted a 6-day grace period, but civilian domestic ballots MUST be physically received by 8:00 p.m. on Election Day.', 'http://legislature.mi.gov/doc.aspx?mcl-168-759', 'MCL § 168.759 & § 168.764a', '2026-05-11', 'static', 'statute_citation', 'Applies to voters requiring absentee-by-mail ballots.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('ef0967095c2a55a4', 'MI', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What specifically must I swear to on the Affidavit of Identity (AOI)?', '["AOI contents","What does the candidate affidavit say?","Reasons an AOI is rejected"]', 'A candidate must swear to their exact name, address, years of residency, citizenship, the specific office sought, and, crucially, that as of the date of the affidavit, all statements, reports, late filing fees, and fines required under the Michigan Campaign Finance Act have been filed or paid.', 'http://legislature.mi.gov/doc.aspx?mcl-168-558', 'MCL § 168.558(2)', '2026-05-11', 'static', 'statute_citation', 'Applies to all candidates filing for office.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('b070160441ce3828', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'When do I have to officially register my campaign committee with the state?', '["Statement of Organization timing","Committee registration threshold","When does a campaign legally begin?"]', 'A candidate must form a Candidate Committee and file a Statement of Organization within 10 days of raising or spending $1,000, or within 10 days of filing an Affidavit of Identity to appear on the ballot, whichever happens first.', 'http://legislature.mi.gov/doc.aspx?mcl-169-224', 'MCL § 169.224(1)', '2026-05-11', 'static', 'statute_citation', 'Applies to all newly formed campaign committees.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('91df19a3ccef167c', 'MI', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the standard campaign finance reporting schedule in an election year?', '["How often do I file finance reports?","Election code reporting cycles","When are my disclosure reports due?"]', 'In an election year, a candidate committee must file a Pre-Election report (11 days before the primary/general), a Post-Election report (30 days after the primary/general), plus standard Quarterly reports in April, July, and October.', 'http://legislature.mi.gov/doc.aspx?mcl-169-233', 'MCL § 169.233', '2026-05-11', 'static', 'statute_citation', 'Applies to all active campaign committees.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('5bf9a4d96f9db05d', 'MI', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the penalty for filing a campaign finance report late?', '["How much are late fees for ethics reports?","Fines for missing a deadline","Bureau of Elections penalties"]', 'For standard reports, the late fee is $25/day capped at $500. For pre-election reports, it is $50/day up to $500 (or $1,000 if the committee raised over $10,000). Late Statement of Organization filing incurs a fee of $10/day capped at $300.', 'http://legislature.mi.gov/doc.aspx?mcl-169-233', 'MCL § 169.233(7)', '2026-05-11', 'static', 'statute_citation', 'Applies to all candidates failing to file disclosure reports on time.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('3e4956faa559fe1f', 'MI', '["federal","state","county","municipal"]', 'ballot_access', 'How do petition signatures for an independent candidate differ from a major party candidate?', '["Independent candidate petition rules","Minor party signature threshold","Qualifying petition vs nominating petition"]', 'Major party candidates file ''Nominating Petitions'' to access the primary. Candidates without political party affiliation must file ''Qualifying Petitions'' directly for the general election ballot, which face different formatting rules, earlier deadlines, and significantly higher signature thresholds.', 'http://legislature.mi.gov/doc.aspx?mcl-168-590b', 'MCL § 168.590b', '2026-05-11', 'static', 'statute_citation', 'Applies to independent candidates seeking ballot access.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('4d7fb8e87dcf3f66', 'MI', '["federal"]', 'ballot_access', 'How many petition signatures does a major party candidate need to run for U.S. Senate?', '["Primary signature requirement for Senate","Statewide major party petition threshold","How many signatures for federal statewide office?"]', 'A major party candidate for U.S. Senate must submit a minimum of 15,000 and a maximum of 30,000 valid signatures. The petition must include at least 100 signatures from each of at least half of the state''s congressional districts (currently 7 districts).', 'http://legislature.mi.gov/doc.aspx?mcl-168-93', 'MCL § 168.93', '2026-05-11', 'static', 'statute_citation', 'Applies to major party candidates for the U.S. Senate.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('2d8591092e309c8e', 'MI', '["state"]', 'ballot_access', 'How many petition signatures does a major party candidate need to run for State Senate or State House?', '["Primary signature requirement for legislature","How many signatures for state rep?","General Assembly petition threshold"]', 'A major party candidate must gather between 500 and 1,000 valid signatures for the State Senate, and between 200 and 400 valid signatures for the State House of Representatives. Alternatively, they may pay a $100 filing fee.', 'http://legislature.mi.gov/doc.aspx?mcl-168-163', 'MCL § 168.163(1)', '2026-05-11', 'static', 'statute_citation', 'Applies to major party candidates for the Michigan Legislature.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('db90a6f0626ba298', 'MI', '["county"]', 'ballot_access', 'How many petition signatures does a candidate need to run for a county-level office like Sheriff or Prosecutor?', '["Signature requirement for local office","How many signatures for county clerk?","Petition threshold for county board"]', 'Signature thresholds for county offices are tiered strictly by county population brackets. The requirement ranges from a minimum of 3 signatures for the smallest counties (under 10,000) up to 20,000 for the largest. Most candidates choose to pay the $100 filing fee alternative.', 'http://legislature.mi.gov/doc.aspx?mcl-168-544f', 'MCL § 168.544f', '2026-05-11', 'static', 'statute_citation', 'Applies to candidates for county-level constitutional offices.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('1e96c4791409a088', 'MI', '["judicial"]', 'election_dates', 'How are Michigan Supreme Court Justices selected and elected?', '["Judicial elections","Are the state supreme court justices elected?","How to run for supreme court"]', 'Michigan uses a distinctive mixed method. Supreme Court candidates are officially nominated by political party conventions, not in the primary election. However, they subsequently appear on the November general election ballot strictly on the nonpartisan section of the ballot.', 'http://legislature.mi.gov/doc.aspx?mcl-168-392', 'MCL § 168.392 & § 168.393', '2026-05-11', 'static', 'statute_citation', 'Applies to candidates for the Michigan Supreme Court.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('2dbb0bfa15f0852d', 'MI', '["state","county","municipal","special_district"]', 'recall_rules', 'What is the procedure for initiating a recall against an elected official in Michigan?', '["Recall election procedures","Removing an official early","Factual sufficiency hearing"]', 'Unlike many states, before a recall petition can even be circulated in Michigan, the sponsor must submit the proposed petition text to the Board of County Election Commissioners for a mandatory hearing to determine if the reasons stated are ''factually and clearly'' drafted.', 'http://legislature.mi.gov/doc.aspx?mcl-168-951a', 'MCL § 168.951a', '2026-05-11', 'static', 'statute_citation', 'Applies to voters initiating a recall effort.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('e00e02fbfd655267', 'MI', '["state","county","municipal","special_district"]', 'recall_rules', 'How many signatures are required to trigger a recall election?', '["Recall signature threshold","Math for recall petitions","How many people need to sign?"]', 'A recall petition must be signed by registered voters in the electoral district equal to at least 25% of the total number of votes cast for the office of governor in that specific district at the last preceding general election.', 'http://legislature.mi.gov/doc.aspx?mcl-168-955', 'MCL § 168.955', '2026-05-11', 'static', 'statute_citation', 'Applies to organizers of a recall petition.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('3d584c96dc21b862', 'MI', '["state"]', 'residency', 'What are the residency and age requirements to run for Governor of Michigan?', '["How old to run for governor?","Residency rules for statewide office","Qualifications for governor"]', 'A candidate for Governor or Lieutenant Governor must be at least 30 years old and must have been a registered elector (voter) in Michigan for the four (4) years next preceding the election.', 'http://legislature.mi.gov/doc.aspx?mcl-Article-V-22', 'Michigan Constitution, Article V, Section 22', '2026-05-11', 'static', 'statute_citation', 'Applies to candidates for Governor and Lieutenant Governor.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('457ccaf8105f97cf', 'MI', '["federal"]', 'residency', 'Do I have to live in the district to run for U.S. House in Michigan?', '["Federal residency rules","Can I run for Congress if I don''t live in the district?","US House eligibility"]', 'No. A candidate for the U.S. House must be at least 25 years old, a citizen for 7 years, and an ''inhabitant'' of Michigan when elected. The U.S. Constitution does not require the candidate to legally reside within the specific boundaries of the congressional district.', 'https://www.michigan.gov/sos/elections/candidates', 'Michigan Secretary of State – Candidate Qualifications', '2026-05-11', 'static', 'official_source_direct', 'Applies to candidates for the United States House of Representatives.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('acaaac8eff035ebb', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Can an individual with a felony conviction vote in Michigan?', '["Felony voting rights","Can felons vote after prison?","Restoration of rights in MI"]', 'Yes. In Michigan, voting rights are automatically restored immediately upon release from incarceration. Individuals with past felony convictions can register and vote while actively on probation or parole.', 'http://legislature.mi.gov/doc.aspx?mcl-168-758b', 'MCL § 168.758b', '2026-05-11', 'static', 'statute_citation', 'Applies to Michigan residents with past felony convictions.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('7d96eeaa449bb267', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What kind of ID is required to vote in person in Michigan?', '["Voter ID at the polls","Voting without an ID","Affidavit alternative for ID"]', 'Voters are asked to show an acceptable photo ID. However, if a voter does not have an acceptable photo ID or forgot to bring it, they can sign an ''Affidavit of Voter Not in Possession of Picture Identification'' and cast a regular ballot.', 'http://legislature.mi.gov/doc.aspx?mcl-168-523', 'MCL § 168.523', '2026-05-11', 'static', 'statute_citation', 'Applies to all in-person voters.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('40a7b60b8ec47e6d', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'How far from the polling place entrance must campaign volunteers stay?', '["Electioneering distance rules","Where can we hold signs at the polls?","Buffer zone restrictions"]', 'Michigan enforces a 100-foot buffer zone extending from any entrance to the building in which the polling place is located. Within this 100-foot zone, campaigning, handing out literature, and wearing campaign apparel are strictly prohibited.', 'http://legislature.mi.gov/doc.aspx?mcl-168-744', 'MCL § 168.744', '2026-05-11', 'static', 'statute_citation', 'Applies to all campaign volunteers and electioneers.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('946d02d287af3aef', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Under what circumstances is a voter issued a provisional ballot?', '["Why do people vote provisionally?","What if a voter isn''t on the rolls?","Envelope ballot rules"]', 'A provisional ballot is issued if a voter''s name does not appear on the registration list for the precinct and their registration cannot be verified by the clerk on Election Day. If the clerk verifies their eligibility within 6 days post-election, the ballot is counted.', 'http://legislature.mi.gov/doc.aspx?mcl-168-813', 'MCL § 168.813', '2026-05-11', 'static', 'statute_citation', 'Applies to voters facing eligibility issues at the polls.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('7b9dcb378433dc7a', 'MI', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'How is the order of candidate names determined on the ballot?', '["Ballot order rules","Do incumbents get listed first?","Is the ballot order randomized?"]', 'In partisan general elections, the party whose candidate received the highest number of votes for Secretary of State in the last election receives the top column/row. Within primary elections, candidate names are rotated systematically by precinct to prevent alphabetical advantage.', 'http://legislature.mi.gov/doc.aspx?mcl-168-703', 'MCL § 168.703 & § 168.569', '2026-05-11', 'static', 'statute_citation', 'Applies to all candidates appearing on the ballot.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('82d2fa9169aaebf5', 'MI', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What happens if a party''s nominee dies or withdraws after the primary but before the general election?', '["Vacancy after qualifying","Replacing a dead candidate","Nominee replacement procedure"]', 'If a nominated candidate dies or becomes disqualified after the primary, the respective political party''s state, district, or county committee is authorized by statute to select a replacement nominee to appear on the general election ballot.', 'http://legislature.mi.gov/doc.aspx?mcl-168-165', 'MCL § 168.165 (Context)', '2026-05-11', 'static', 'statute_citation', 'Applies to party committees filling a vacancy on the ballot.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('f1da88d17d51e72e', 'MI', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the 48-hour reporting rule for late contributions?', '["Late fee for large pre-election donations","Penalty for missing the late contribution report","Fines for late big checks"]', 'Any contribution of $500 or more received between the 15th day and the 3rd day before an election must be reported to the filing official within 48 hours of receipt.', 'http://legislature.mi.gov/doc.aspx?mcl-169-232', 'MCL § 169.232', '2026-05-11', 'per_cycle', 'statute_citation', 'Applies to campaigns receiving large late contributions.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('4e17ab28b2836617', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What are the specific deadlines for the November 2026 General Election?', '["When is everything due for the fall election?","2026 general election schedule","Mail and registration cutoff dates"]', 'For the November 3, 2026 General Election: standard registration closes October 19; early voting runs October 24 through November 1; mail ballot requests are due by 5:00 p.m. October 30; and domestic mail ballots must be received by 8:00 p.m. on Election Day.', 'http://legislature.mi.gov/doc.aspx?mcl-168-641', 'MCL § 168 (Contextual Timeline)', '2026-05-11', 'per_cycle', 'statute_citation', 'Applies to voters and campaigns in the 2026 general election.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('e3e5be70a1214e31', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What are the exact dates for the early voting period in the 2026 General Election?', '["When does Proposal 2 voting start in 2026?","In-person early voting dates","Early voting calendar"]', 'Under the constitutional mandate of nine consecutive days ending the Sunday before the election, early in-person voting for the 2026 General Election will begin on Saturday, October 24, 2026, and end on Sunday, November 1, 2026.', 'http://legislature.mi.gov/doc.aspx?mcl-Article-II-4', 'Michigan Constitution, Article II, Section 4(1)(m)', '2026-05-11', 'per_cycle', 'statute_citation', 'Applies to campaigns organizing early GOTV operations.', 'batch_2026-05-11T16-22-18_michigan_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('a76c27c9585fa70b', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Who is legally allowed to serve as an election challenger (poll watcher) in Michigan?', '["Poll watcher qualifications","Can I bring in observers from out of state?","Who can be an election observer?"]', 'An election challenger in Michigan MUST be a registered elector (voter) of the State of Michigan. Furthermore, they cannot self-appoint; they must be officially appointed and credentialed by a recognized political party or an authorized incorporated organization.', 'http://legislature.mi.gov/doc.aspx?mcl-168-730', 'MCL § 168.730', '2026-05-11', 'static', 'statute_citation', 'Applies to campaigns appointing election observers.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('67b7b5a5f0b95924', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Are campaign signs allowed to be placed on state highway rights-of-way?', '["Can I put signs in the median?","Highway campaign sign rules","Does MDOT take down political signs?"]', 'No. The Michigan Department of Transportation (MDOT) strictly prohibits the placement of political campaign signs within the right-of-way of any state highway, and unauthorized signs will be removed.', 'https://www.michigan.gov/mdot/about/media/pressreleases/2022/09/20/political-signs', 'Michigan Department of Transportation (MDOT) – Sign Rules', '2026-05-11', 'static', 'official_source_direct', 'Applies to all campaigns placing signage.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('f2ade0af2d2957b5', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What are the disclaimer rules for campaign robocalls and SMS texts?', '["Robocall rules","Voice call political advertising","Do auto-dialers need to say who paid for it?"]', 'Under the Michigan Campaign Finance Act, any political advertisement, whether printed, broadcast, or sent via electronic mass media (like robocalls or mass SMS), must clearly state ''Paid for by'' followed by the name and address of the committee paying for the communication.', 'http://legislature.mi.gov/doc.aspx?mcl-169-247', 'MCL § 169.247(1)', '2026-05-11', 'static', 'statute_citation', 'Applies to all campaigns conducting phone or SMS outreach.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('56b2638509c0d294', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Does my campaign website or digital ad require a ''Paid for by'' disclaimer?', '["Digital advertising disclaimers","Do Facebook ads need disclosures?","Website paid-for rules"]', 'Yes. Digital advertising and campaign websites are subject to the same ''Paid for by'' identification requirements as traditional print media under the Michigan Campaign Finance Act.', 'http://legislature.mi.gov/doc.aspx?mcl-169-247', 'MCL § 169.247', '2026-05-11', 'static', 'statute_citation', 'Applies to all campaigns running digital advertisements.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('9eb623461738c155', 'MI', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I use campaign funds to pay my personal mortgage or buy groceries?', '["Personal use of campaign funds","Can I pay rent with donor money?","Impermissible uses of campaign cash"]', 'No. The Michigan Campaign Finance Act explicitly states that a candidate committee shall not make an expenditure for the personal benefit of the candidate or any other person.', 'http://legislature.mi.gov/doc.aspx?mcl-169-245', 'MCL § 169.245(2)', '2026-05-11', 'static', 'statute_citation', 'Applies to all candidates and officeholders.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('a75c108fa53d3593', 'MI', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How do I value an in-kind contribution of goods or services?', '["In-kind valuation","How much is a donated venue worth?","Reporting free services"]', 'In-kind contributions must be reported at their fair market value at the time the contribution is made, and the value applies directly against the contributor''s individual per-cycle contribution limits.', 'http://legislature.mi.gov/doc.aspx?mcl-169-209', 'MCL § 169.209(3)', '2026-05-11', 'static', 'statute_citation', 'Applies to all campaigns accepting non-monetary donations.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('67037fb1d130747d', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is an Independent Expenditure Committee (Super PAC) under Michigan law?', '["Super PAC rules","Can a PAC accept corporate money?","Independent spending"]', 'An Independent Expenditure Committee (often called a Super PAC) is a committee that may accept unlimited contributions from corporations and unions, but it is strictly prohibited from coordinating with, or making direct contributions to, candidate committees.', 'http://legislature.mi.gov/doc.aspx?mcl-169-224b', 'MCL § 169.224b', '2026-05-11', 'static', 'statute_citation', 'Applies to groups making independent political expenditures.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('d294c86dff6f9195', 'MI', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can two candidates host a joint fundraising event and split the costs?', '["Joint fundraising rules","Sharing campaign event costs","Splitting money with another candidate"]', 'Yes. Candidates may engage in joint fundraising. They must designate a secondary depository for the event, proportionally allocate the costs of the fundraiser, and transfer the appropriately tracked contributions to their respective candidate committees.', 'http://legislature.mi.gov/doc.aspx?mcl-169-244', 'MCL § 169.244(1)', '2026-05-11', 'static', 'statute_citation', 'Applies to campaigns pooling resources for fundraising.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('1fc1d5fdff4e4b51', 'MI', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'When does a Political Action Committee (PAC) have to register with the state?', '["PAC registration threshold","When do independent groups have to disclose?","Threshold for third-party reporting"]', 'An entity must register as a PAC by filing a Statement of Organization within 10 days of receiving contributions or making expenditures that aggregate $500 or more in a calendar year.', 'http://legislature.mi.gov/doc.aspx?mcl-169-224', 'MCL § 169.224(1)', '2026-05-11', 'per_cycle', 'statute_citation', 'Applies to PACs operating in Michigan.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('700838920c0ded9e', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How long must my campaign treasurer keep our financial records?', '["Record retention rules","How long do I save receipts?","Keeping finance reports post-election"]', 'The committee treasurer must preserve all accounts, records, bills, and receipts for five (5) years following the date the related campaign statement is filed.', 'http://legislature.mi.gov/doc.aspx?mcl-169-222', 'MCL § 169.222', '2026-05-11', 'static', 'statute_citation', 'Applies to all campaign treasurers.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('ea30ecec67574841', 'MI', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How do I officially close my campaign account after the election?', '["Ending my campaign reporting obligations","Filing the termination report","How to stop filing ethics reports"]', 'To terminate a committee, a candidate must file a dissolution campaign statement confirming that the committee has no assets, no outstanding debts, and will no longer receive contributions or make expenditures.', 'http://legislature.mi.gov/doc.aspx?mcl-169-224', 'MCL § 169.224(8)', '2026-05-11', 'static', 'statute_citation', 'Applies to all candidates wishing to terminate their campaign committee.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('0bd6ff6af753796f', 'MI', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What must I do with my surplus campaign funds upon termination?', '["Disposing of leftover money","Can I keep my campaign cash?","Final campaign account closure"]', 'Surplus funds may be returned to contributors, donated to a tax-exempt 501(c)(3) charity, given to a political party committee, or transferred to another candidate committee of the same candidate for a different office.', 'http://legislature.mi.gov/doc.aspx?mcl-169-245', 'MCL § 169.245(2)', '2026-05-11', 'static', 'statute_citation', 'Applies to candidates distributing surplus funds.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('ffd6e3317f9c4ca7', 'MI', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can my campaign accept donations from foreign nationals?', '["Accepting money from non-citizens","Foreign contributions in MI","Can someone from overseas donate?"]', 'No. Under federal preemption and the Michigan Campaign Finance Act, foreign nationals are strictly prohibited from making contributions, and candidate committees are strictly prohibited from soliciting or accepting them.', 'http://legislature.mi.gov/doc.aspx?mcl-169-256', 'MCL § 169.256', '2026-05-11', 'static', 'statute_citation', 'Applies to all campaigns and political committees.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('1beda982e6d90337', 'MI', '["state"]', 'finance_ethics', 'Do I have to file a Statement of Financial Interests to get on the ballot?', '["Ethics paperwork for candidates","When do I file financial disclosures?","Public Officer Financial Disclosure Act"]', 'Yes, for certain state offices. Following Proposal 1 of 2022 (implemented by PA 281 of 2023), candidates for state executive offices and the state legislature must file a financial disclosure report with the Department of State by May 15 of the election year.', 'http://legislature.mi.gov/doc.aspx?mcl-15-703', 'MCL § 15.703 (PA 281 of 2023)', '2026-05-11', 'static', 'statute_citation', 'Applies to candidates for state executive and legislative offices.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('0a313e89810f71cb', 'MI', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Who oversees candidate financial disclosures and enforces ethics rules in Michigan?', '["Who handles ethics complaints?","Where do I file the campaign reports?","Ethics regulatory body"]', 'The Michigan Department of State, specifically the Bureau of Elections, serves as the primary filing official and regulatory body responsible for administering the Campaign Finance Act and investigating ethics complaints.', 'https://www.michigan.gov/sos/elections/disclosure/cfr', 'Michigan Bureau of Elections – Campaign Finance', '2026-05-11', 'static', 'official_source_direct', 'Applies to all candidates and political committees.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('95de2caec1d72ee5', 'MI', '["state"]', 'election_dates', 'How are vacancies in the State Legislature filled?', '["Special elections for state rep","Filling an empty senate seat","What happens if a legislator resigns?"]', 'When a vacancy occurs in the office of State Senator or State Representative, the Governor may call a special election in that electoral district or direct that the vacancy be filled at the next general election.', 'http://legislature.mi.gov/doc.aspx?mcl-168-634', 'MCL § 168.634', '2026-05-11', 'static', 'statute_citation', 'Applies to the replacement of sitting legislators.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('55588b9a2c9a88ff', 'MI', '["state"]', 'residency', 'What are the residency and age requirements to run for the State Legislature in Michigan?', '["How old to run for state house?","Residency rules for state senate","District residency timeline"]', 'A candidate for State Senator or State Representative must be at least 21 years of age, a citizen of the United States, and an elector (registered voter) of the district they seek to represent for at least 30 days prior to the filing deadline.', 'http://legislature.mi.gov/doc.aspx?mcl-168-161', 'MCL § 168.161', '2026-05-11', 'static', 'statute_citation', 'Applies to candidates for the Michigan Legislature.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('fc321da55aeb5b1c', 'MI', '["federal","state","county","municipal"]', 'candidate_eligibility', 'Can I run for Mayor and State Legislature at the same time?', '["Dual candidacy rules in Michigan","Can I run for two offices at once?","Running for multiple seats on one ballot"]', 'No. Under Michigan law, a candidate cannot be placed on the ballot for more than one office at the same election, with very limited minor exceptions for non-conflicting local offices like precinct delegate or school board.', 'http://legislature.mi.gov/doc.aspx?mcl-168-558', 'MCL § 168.558(5)', '2026-05-11', 'static', 'statute_citation', 'Applies to all candidates attempting to run simultaneously for multiple offices.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('ba20f9bf22fece38', 'MI', '["state","county","municipal","special_district"]', 'recall_rules', 'How quickly does a recall election happen once the petition is approved?', '["Recall election scheduling","When does the recall vote happen?","Timeline for removing an official"]', 'If a recall petition is deemed legally sufficient, the recall election is scheduled to be held on the next regular election date (May or November) that is at least 95 days after the date the petition was filed.', 'http://legislature.mi.gov/doc.aspx?mcl-168-963', 'MCL § 168.963', '2026-05-11', 'static', 'statute_citation', 'Applies to organizers of a recall petition.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('d93cb3a865cd25e9', 'MI', '["judicial"]', 'election_dates', 'How are Court of Appeals and Circuit Court judges selected?', '["Are lower court judges elected?","Circuit Court elections","Selection process for district judges"]', 'Judges of the Court of Appeals, Circuit Courts, and District Courts are elected directly by the voters on nonpartisan ballots. Incumbent judges may secure a place on the ballot simply by filing an Affidavit of Candidacy rather than nominating petitions.', 'http://legislature.mi.gov/doc.aspx?mcl-Article-VI-12', 'Michigan Constitution, Article VI, Section 12', '2026-05-11', 'static', 'statute_citation', 'Applies to candidates for Michigan lower courts.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('2a7b6ba924c90ea2', 'MI', '["judicial"]', 'election_dates', 'How long are the terms for elected judges in Michigan?', '["Judicial term lengths","How long does a supreme court justice serve?","Circuit court terms"]', 'Justices of the Michigan Supreme Court are elected to serve eight-year terms. Judges of the Court of Appeals, Circuit Courts, and District Courts are elected to serve six-year terms.', 'http://legislature.mi.gov/doc.aspx?mcl-Article-VI-2', 'Michigan Constitution, Article VI, Section 2 & Section 9', '2026-05-11', 'static', 'statute_citation', 'Applies to all judicial candidates and elected judges.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('3600c33d26c3dcde', 'MI', '["municipal"]', 'election_dates', 'Who runs municipal elections in the City of Detroit?', '["Detroit Election Commission","Who is in charge of voting in Detroit?","City Clerk authority"]', 'In Detroit, elections are administered by the Detroit Election Commission, a uniquely powerful municipal body established by the City Charter, consisting of the City Clerk, the President of the City Council, and the Corporation Counsel.', 'https://detroitmi.gov/departments/elections/detroit-election-commission', 'Detroit City Charter (Context)', '2026-05-11', 'static', 'official_source_direct', 'Applies to campaigns operating within the City of Detroit.', 'batch_2026-05-11T16-22-18_michigan_full_v1'),
  ('21a45ba3a9b876fa', 'MI', '["federal","state","county","municipal","judicial"]', 'election_dates', 'Who officially certifies the results of statewide elections in Michigan?', '["Board of State Canvassers","Who declares the winner?","Election certification process"]', 'Statewide, federal, and state legislative elections are certified by the Board of State Canvassers, a four-member bipartisan panel (two Republicans, two Democrats) appointed by the Governor. They meet following the election to canvass and officially certify the results.', 'http://legislature.mi.gov/doc.aspx?mcl-168-841', 'MCL § 168.841', '2026-05-11', 'static', 'statute_citation', 'Applies to the post-election certification phase.', 'batch_2026-05-11T16-22-18_michigan_full_v1')
